import{f as t,o as r,c as e,a9 as n}from"./chunks/framework.BSdZLMbP.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段21-项目规范与代码审查.md","filePath":"S6-Go/阶段21-项目规范与代码审查.md","lastUpdated":1780660866000}'),a={name:"S6-Go/阶段21-项目规范与代码审查.md"};function s(i,o,l,d,g,c){return r(),e("div",null,[...o[0]||(o[0]=[n('<h2 id="📝-阶段二十一-项目规范与代码审查-code-review" tabindex="-1">📝 阶段二十一：项目规范与代码审查 (Code Review) <a class="header-anchor" href="#📝-阶段二十一-项目规范与代码审查-code-review" aria-label="Permalink to &quot;📝 阶段二十一：项目规范与代码审查 (Code Review)&quot;">​</a></h2><h3 id="_21-1-最佳实践与反模式" tabindex="-1">21.1 最佳实践与反模式 <a class="header-anchor" href="#_21-1-最佳实践与反模式" aria-label="Permalink to &quot;21.1 最佳实践与反模式&quot;">​</a></h3><h4 id="q76-go-项目中常见的-反模式-anti-patterns-有哪些" tabindex="-1">Q76: Go 项目中常见的“反模式”（Anti-patterns）有哪些？ <a class="header-anchor" href="#q76-go-项目中常见的-反模式-anti-patterns-有哪些" aria-label="Permalink to &quot;Q76: Go 项目中常见的“反模式”（Anti-patterns）有哪些？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：代码异味、过度设计、接口滥用、包循环依赖。</p><p><strong>💡 记忆关键词</strong>：接口滥用、循环依赖、全局变量、错误忽略</p><p><strong>答案要点</strong>：</p><ul><li><strong>接口滥用</strong>：不要预先定义接口，应在需要解耦或测试时再定义（&quot;Accept interfaces, return structs&quot;）。</li><li><strong>包循环依赖</strong>：通过引入 <code>internal</code> 包或重构层级解决。</li><li><strong>全局变量</strong>：避免使用全局状态，改用依赖注入（DI）传递配置和客户端。</li><li><strong>错误忽略</strong>：禁止使用 <code>_</code> 忽略 <code>error</code>，必须显式处理或包装。</li></ul><p><strong>📝 一句话总结</strong>：反模式四宗罪，接口滥用循环依；全局变量错误忽，避免过度设计先。</p><h4 id="q77-如何设计一个可扩展的-go-项目结构" tabindex="-1">Q77: 如何设计一个可扩展的 Go 项目结构？ <a class="header-anchor" href="#q77-如何设计一个可扩展的-go-项目结构" aria-label="Permalink to &quot;Q77: 如何设计一个可扩展的 Go 项目结构？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：Standard Go Project Layout、<code>cmd</code>/<code>internal</code>/<code>pkg</code> 分层。</p><p><strong>💡 记忆关键词</strong>：cmd入口、internal私有、pkg公共、api契约</p><p><strong>答案要点</strong>：</p><ul><li><strong><code>cmd/</code></strong>：应用入口（如 <code>cmd/server/main.go</code>），仅包含初始化和启动逻辑。</li><li><strong><code>internal/</code></strong>：私有业务逻辑，禁止外部包导入（如 <code>internal/service</code>, <code>internal/handler</code>）。</li><li><strong><code>pkg/</code></strong>：可复用的公共库，可被外部项目引用（如 <code>pkg/logger</code>, <code>pkg/utils</code>）。</li><li><strong><code>api/</code></strong>：Protobuf 定义、OpenAPI 规范。</li><li><strong>优势</strong>：清晰的分层架构，便于测试、维护和团队协作。</li></ul><p><strong>📝 一句话总结</strong>：cmd入口internal私，pkg公共api契；分层架构清晰明，测试维护协作行。</p><h3 id="_21-2-配置与依赖管理" tabindex="-1">21.2 配置与依赖管理 <a class="header-anchor" href="#_21-2-配置与依赖管理" aria-label="Permalink to &quot;21.2 配置与依赖管理&quot;">​</a></h3><h4 id="q78-生产环境配置管理最佳实践" tabindex="-1">Q78: 生产环境配置管理最佳实践？ <a class="header-anchor" href="#q78-生产环境配置管理最佳实践" aria-label="Permalink to &quot;Q78: 生产环境配置管理最佳实践？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：环境变量、配置中心、热更新、敏感信息保护。</p><p><strong>💡 记忆关键词</strong>：12-Factor、viper配置、热更新、Vault加密</p><p><strong>答案要点</strong>：</p><ul><li><strong>12-Factor App</strong>：配置与代码分离，使用环境变量注入。</li><li><strong>配置库</strong>：使用 <code>viper</code> 支持多格式（YAML/JSON/ENV）和多来源（本地/远程）。</li><li><strong>热更新</strong>：监听文件变化或配置中心推送（如 etcd Watch），动态刷新配置无需重启。</li><li><strong>安全</strong>：敏感信息（DB 密码、API Key）存入 Vault 或 K8s Secrets，禁止硬编码。</li></ul><p><strong>📝 一句话总结</strong>：配置代码要分离，viper多源格式齐；热更新来免重启，Vault加密保安全。</p><hr>',25)])])}const h=t(a,[["render",s]]);export{_ as __pageData,h as default};
